#include<bits/stdc++.h>
using namespace std;
#define mian main
#define whlie while
//#define Yes yes
//#define No; no
bool flag;
int t,n,b;
int a[100005];
vector<int> e[100005];

int dfs(int x,int f){
	if(e[x].size()==1&&e[x][0]==f){
		return a[x];
	}
	int ans=0,p=0;
	for(int i:e[x])
	{
		if(i!=f)
		{
			int l=dfs(i,x);
			if(l)
			{
				p++;
				ans+=l;
			}
		}
	}
	ans+=a[x];
	if((ans!=b&&p>1)||p>2) flag=0;
	return ans;
}
int mian(){
	cin>>t;
	whlie (t--){

		flag=1;
		b=0;
		cin>>n;
		for(int i=1;i<=n;i++){
			e[i].clear();
			cin>>a[i];
			b+=a[i];
		}
        for(int i=1;i<n;i++)
		{
			int x,y;
			cin>>x>>y;
			e[x].push_back(y);
			e[y].push_back(x);
		}
		dfs(1,0);
		if(flag) cout<<"Yes\n";
		else cout<<"No\n";

	}
	return 0;
}
